import { describe, it, expect } from 'vitest';
import {
  isValidOrderStatusTransition,
  validateOrderStatusTransition,
  validateOrderItems,
} from '../../src/validators/order.validator.js';

describe('order.validator', () => {
  describe('isValidOrderStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidOrderStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidOrderStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidOrderStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidOrderStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidOrderStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidOrderStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidOrderStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidOrderStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidOrderStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidOrderStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidOrderStatusTransition('cancelled', 'confirmed')).toBe(false);
    });
  });

  describe('validateOrderStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateOrderStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateOrderStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });
  });

  describe('validateOrderItems', () => {
    it('should not throw for non-empty items', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() => validateOrderItems([])).toThrow('at least one item');
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateUserExists,
  validateEmailAvailable,
  validateEmailNotTaken,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user.validator', () => {
  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      expect(() => validateUserExists(makeUser(), 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validateEmailAvailable', () => {
    it('should not throw when no user has the email', () => {
      expect(() => validateEmailAvailable(undefined, 'new@example.com')).not.toThrow();
    });

    it('should throw when a user already has the email', () => {
      expect(() => validateEmailAvailable(makeUser(), 'alice@example.com')).toThrow(
        'User with email alice@example.com already exists',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when no user has the email', () => {
      expect(() => validateEmailNotTaken(undefined, 'new@example.com')).not.toThrow();
    });

    it('should throw when a user already has the email', () => {
      expect(() => validateEmailNotTaken(makeUser(), 'alice@example.com')).toThrow(
        'Email alice@example.com is already in use',
      );
    });
  });
});

